158→            // For j != i and j != target, arr[j] unchanged
159→            assert forall j :: 0 <= j < n && j != i && j != target ==> newSeq[j] == oldSeq[j];
160→            // So any j in oldCorrect with j != i and j != target is still in CorrectIndices(newSeq)
161→            assert forall j :: j in oldCorrect && j != i && j != target ==> j in CorrectIndices(newSeq);
162→            // Even if i was in oldCorrect, we still gained target which wasn't
163→            // So |CorrectIndices(newSeq)| >= |oldCorrect - {i}| + 1 >= |oldCorrect|
164→            // Actually, we need |CorrectIndices(newSeq)| > |oldCorrect|
165→            // oldCorrect - {i} <= CorrectIndices(newSeq) (removing at most i)
166→            // target in CorrectIndices(newSeq) and target !in oldCorrect
167→            // So CorrectIndices(newSeq) >= (oldCorrect - {i}) + {target}
168→            // If i was not in oldCorrect: CorrectIndices(newSeq) >= oldCorrect + {target}, so size increased
169→            // If i was in oldCorrect: CorrectIndices(newSeq) >= (oldCorrect - {i}) + {target},
170→            //   and |oldCorrect - {i}| = |oldCorrect| - 1, so |(oldCorrect - {i}) + {target}| = |oldCorrect|
171→            //   But we might have gained even more. Hmm, this case is tricky.
172→            //   Wait, if i was in oldCorrect, then oldSeq[i] == i+1.
173→            //   After swap, arr[i] = temp = oldSeq[target].
174→            //   We need arr[i] != i+1 (i.e., we lost i from correct).
175→            //   But could arr[i] == i+1? That would mean temp == i+1, i.e., oldSeq[target] == i+1.
176→            //   But target = oldSeq[i] - 1 = (i+1) - 1 = i. So target == i. But we asserted target != i.
177→            //   Contradiction! So if i was in oldCorrect, target == i, which can't happen.
178→            //   Therefore i was NOT in oldCorrect.
179→            assert i !in oldCorrect by {
180→              if i in oldCorrect {
181→                assert oldSeq[i] == i + 1;
182→                assert target == oldSeq[i] - 1 == i;
183→                assert false;
184→              }
185→            }
186→            assert oldCorrect <= CorrectIndices(newSeq) by {
187→              forall j | j in oldCorrect
188→                ensures j in CorrectIndices(newSeq)
189→              {
190→                if j == target {
191→                  assert j in CorrectIndices(newSeq);
192→                } else if j == i {
193→                  assert false; // i !in oldCorrect
194→                } else {
195→                  assert newSeq[j] == oldSeq[j];
196→                  assert j in CorrectIndices(newSeq);
197→                }
198→              }
199→            }
200→            assert target in CorrectIndices(newSeq) && target !in oldCorrect;
201→            assert CorrectIndices(newSeq) >= oldCorrect + {target};
202→            // Prove |CorrectIndices(newSeq)| > |oldCorrect|
203→            StrictSupersetHasLargerCardinality(oldCorrect, CorrectIndices(newSeq));
204→            // Prove n - |CorrectIndices(newSeq)| >= 0
205→            CorrectIndicesBound(newSeq);
206→            assert startCorrect <= CorrectIndices(newSeq);
207→        }
208→        i := i + 1;
209→    }
210→
211→    // Loop 3: find first missing positive
212→    i := 0;
213→    while i < n
214→      invariant 0 <= i <= n
215→      invariant arr.Length == n
216→      invariant multiset(arr[..]) == multiset(nums)
217→      invariant forall j :: 0 <= j < i ==> arr[j] == j + 1
218→      invariant forall j :: 0 <= j < n ==>
219→        (arr[j] == j + 1 || arr[j] < 1 || arr[j] > n || arr[arr[j] - 1] == arr[j])
220→    {
221→        if arr[i] != i + 1 {
222→            assert !SeqContains(arr[..], i + 1) by {
223→              if SeqContains(arr[..], i + 1) {
224→                var k :| 0 <= k < |arr[..]| && arr[..][k] == i + 1;
225→                assert arr[k] == i + 1;
226→                assert k != i;
227→                assert 1 <= arr[k] <= n;
228→                assert arr[arr[k] - 1] == arr[k];
229→                assert arr[i] == i + 1;
230→                assert false;
231→              }
232→            }
233→            MultisetEqPreservesSeqContains(arr[..], nums, i + 1);
234→
235→            assert forall x :: 1 <= x <= i ==> SeqContains(nums, x) by {
236→              forall x | 1 <= x <= i
237→                ensures SeqContains(nums, x)
238→              {
239→                assert arr[x - 1] == x;
240→                assert arr[..][x - 1] == x;
241→                assert SeqContains(arr[..], x);
242→                MultisetEqPreservesSeqContains(arr[..], nums, x);
243→              }
244→            }
245→            return i + 1;
246→        }
247→        i := i + 1;
248→    }
249→
250→    assert forall x :: 1 <= x <= n ==> SeqContains(nums, x) by {
251→      forall x | 1 <= x <= n
252→        ensures SeqContains(nums, x)
253→      {
254→        assert arr[x - 1] == x;
255→        assert arr[..][x - 1] == x;
256→        assert SeqContains(arr[..], x);
257→        MultisetEqPreservesSeqContains(arr[..], nums, x);
258→      }
259→    }
260→
261→    assert !SeqContains(nums, n + 1) by {
262→      if SeqContains(nums, n + 1) {
263→        SeqContainsImpliesMultisetContains(nums, n + 1);
264→        assert n + 1 in multiset(arr[..]);
265→        MultisetContainsImpliesSeqContains(arr[..], n + 1);
266→        var k :| 0 <= k < |arr[..]| && arr[..][k] == n + 1;
267→        assert arr[k] == n + 1;
268→        assert arr[k] == k + 1;
269→        assert k == n;
270→        assert k < n;
271→        assert false;
272→      }
273→    }
274→
275→    return n + 1;
